  double get resolvedFloorZoom =>
      max(configuredFloorZoom, spanLimitedFloorZoom);

  /// True when the contextual cycle floor had to yield to the per-leg span cap.
  bool get floorCappedBySpan => configuredFloorZoom < spanLimitedFloorZoom;
}

/// Replayable target range for one auto-explore cycle step.
class AutoExploreZoomTargetRange {
  static const double collapseEpsilon = 1e-9;

  final double peakZoom;
  final double floorZoom;

  const AutoExploreZoomTargetRange({
    required this.peakZoom,
    required this.floorZoom,
  }) : assert(floorZoom <= peakZoom, 'floorZoom must not exceed peakZoom');

  /// Builds a target range that stays ordered after precision caps are applied.
  ///
  /// The floor candidate is derived from the cycle base, while the peak can be
  /// lowered by a module precision hard max. Without this normalization a base
  /// above the hard max makes zoom-in target a lower value than zoom-out.
  factory AutoExploreZoomTargetRange.fromCandidates({
    required double peakZoom,
    required double floorZoom,
  }) {
    return AutoExploreZoomTargetRangeResolution.fromCandidates(
      peakZoom: peakZoom,
      floorZoom: floorZoom,
    ).range;
  }

  bool get isCollapsed => (peakZoom - floorZoom).abs() < collapseEpsilon;

  double targetZoom({required bool zoomingIn}) {
    if (isCollapsed) {
      // Collapsed plans must remain inside the resolved target range. Returning
      // the cycle base can bypass a precision hard-max when floor and peak both
      // collapse below the current/base zoom.
      return min(peakZoom, floorZoom);
    }
    return zoomingIn ? peakZoom : floorZoom;
  }
}

/// Replayable ordering step for target-range candidates.
///
/// Target selection derives the peak and floor from different assumptions: the
/// peak may be lowered by module precision, while the floor comes from the cycle
/// base. This value exposes when the floor candidate had to yield to the
/// precision-capped peak instead of silently relying on `min(floor, peak)`.
class AutoExploreZoomTargetRangeResolution {
  final double requestedPeakZoom;
  final double requestedFloorZoom;
  final AutoExploreZoomTargetRange range;

  const AutoExploreZoomTargetRangeResolution({
    required this.requestedPeakZoom,
    required this.requestedFloorZoom,
    required this.range,
  });

  factory AutoExploreZoomTargetRangeResolution.fromCandidates({
    required double peakZoom,
    required double floorZoom,
  }) {
    return AutoExploreZoomTargetRangeResolution(
      requestedPeakZoom: peakZoom,
      requestedFloorZoom: floorZoom,
      range: AutoExploreZoomTargetRange(
        peakZoom: peakZoom,
        floorZoom: min(floorZoom, peakZoom),
      ),
    );
  }

  bool get floorCappedByPeak => requestedFloorZoom > range.floorZoom;
}

/// Sanitized inputs used for one replayable auto-explore target decision.
///
/// This exposes the hidden fallback order used by the service: current zoom is
/// sanitized first, then a missing cycle base adopts that sanitized current
/// value. A malformed non-null cycle base is still sanitized independently.
class AutoExploreZoomPlanInputs {
  final double currentZoom;
  final double baseZoom;

  const AutoExploreZoomPlanInputs({
    required this.currentZoom,
    required this.baseZoom,
  });

  factory AutoExploreZoomPlanInputs.fromBounds({
    required AutoExploreZoomBounds bounds,
    required double currentZoom,
    required double? cycleBaseZoom,
  }) {
    final current = bounds.clamp(currentZoom);
    return AutoExploreZoomPlanInputs(
      currentZoom: current,
      baseZoom: bounds.clamp(cycleBaseZoom ?? current),
    );
  }
}

/// Replayable target-selection data for one auto-explore cycle step.
class AutoExploreZoomTargetPlan {
  final AutoExploreZoomPlanInputs inputs;
  final AutoExplorePeakZoomCandidates peakCandidates;
  final double peakZoom;
  final double floorZoom;
  final bool zoomingIn;

  const AutoExploreZoomTargetPlan({
    required this.inputs,
    required this.peakCandidates,
    required this.peakZoom,
    required this.floorZoom,
    required this.zoomingIn,
  }) : assert(floorZoom <= peakZoom, 'floorZoom must not exceed peakZoom');

  double get currentZoom => inputs.currentZoom;
  double get baseZoom => inputs.baseZoom;

  AutoExploreZoomTargetRange get targetRange =>
      AutoExploreZoomTargetRange.fromCandidates(
        peakZoom: peakZoom,
        floorZoom: floorZoom,
      );

  bool get isCollapsed => targetRange.isCollapsed;

  bool get respectsPrecisionHardMax => peakZoom <= peakCandidates.hardMaxZoom;

  double get targetZoom => targetRange.targetZoom(zoomingIn: zoomingIn);
}

/// Pure zoom-planning logic for [AutoExploreService].
///
/// Keeping target selection side-effect free makes the precision assumptions
/// replayable in tests without constructing timers or a renderer controller.
class AutoExploreZoomPlanner {
  final AutoExploreConfig config;
  final DeepZoomPrecisionPolicy precisionPolicy;

  const AutoExploreZoomPlanner({
    required this.config,
    this.precisionPolicy = const DeepZoomPrecisionPolicy(),
  });

  AutoExploreZoomBounds get _bounds => AutoExploreZoomBounds.fromConfig(config);
  AutoExploreCycleShape get _cycleShape =>
      AutoExploreCycleShape.fromConfig(config);

  double clampZoom(double zoom) => _bounds.clamp(zoom);

  double hardMaxZoomFor(String moduleId) {
    final headroom = AutoExplorePrecisionHeadroom.normalize(
      config.precisionHeadroom,
    );
    final safeThreshold = precisionPolicy.thresholdFor(moduleId) * headroom;
    return _bounds.clamp(safeThreshold);
  }

  AutoExplorePeakZoomCandidates peakZoomCandidates({
    required double baseZoom,
    required String moduleId,
  }) {
    final base = clampZoom(baseZoom);
    final hardMax = hardMaxZoomFor(moduleId);
    final cycleShape = _cycleShape;
    final maxSpanRatio = cycleShape.maxLegSpanRatio;

    return AutoExplorePeakZoomCandidates(
      baseZoom: base,
      minProgressZoom: clampZoom(base * 1.25),
      configuredPeakZoom: clampZoom(base * cycleShape.cycleMaxMultiplier),
      spanLimitedPeakZoom: clampZoom(base * maxSpanRatio),
      hardMaxZoom: hardMax,
    );
  }

  double computePeakZoom({
    required double baseZoom,
    required String moduleId,
  }) {
    return peakZoomCandidates(
      baseZoom: baseZoom,
      moduleId: moduleId,
    ).resolvedPeakZoom;
  }

  AutoExploreFloorZoomCandidates floorZoomCandidates(double baseZoom) {
    final bounds = _bounds;
    final base = bounds.clamp(baseZoom);
    final cycleShape = _cycleShape;
    final configuredFloor = base / cycleShape.cycleMaxMultiplier;
    final spanLimitedFloor = base / cycleShape.maxLegSpanRatio;

    return AutoExploreFloorZoomCandidates(
      baseZoom: base,
      configuredFloorZoom: bounds.clamp(max(bounds.minZoom, configuredFloor)),
      spanLimitedFloorZoom: bounds.clamp(max(bounds.minZoom, spanLimitedFloor)),
    );
  }

  double computeFloorZoom(double baseZoom) {
    return floorZoomCandidates(baseZoom).resolvedFloorZoom;
  }

  AutoExploreZoomPlanInputs planInputs({
    required double currentZoom,
    required double? cycleBaseZoom,
  }) {
    return AutoExploreZoomPlanInputs.fromBounds(
      bounds: _bounds,
      currentZoom: currentZoom,
      cycleBaseZoom: cycleBaseZoom,
    );
  }

  AutoExploreZoomTargetPlan planNextTarget({
    required double currentZoom,
    required double? cycleBaseZoom,
    required bool zoomingIn,
    required String moduleId,
  }) {
    final inputs = planInputs(
      currentZoom: currentZoom,
      cycleBaseZoom: cycleBaseZoom,
    );
    final peakCandidates = peakZoomCandidates(
      baseZoom: inputs.baseZoom,
      moduleId: moduleId,
    );
    final rangeResolution = AutoExploreZoomTargetRangeResolution.fromCandidates(
      peakZoom: peakCandidates.resolvedPeakZoom,
      floorZoom: computeFloorZoom(inputs.baseZoom),
    );

    return AutoExploreZoomTargetPlan(
      inputs: inputs,
      peakCandidates: peakCandidates,
      peakZoom: rangeResolution.range.peakZoom,
      floorZoom: rangeResolution.range.floorZoom,
      zoomingIn: zoomingIn,
    );
  }

  double nextTargetZoom({
    required double currentZoom,
    required double? cycleBaseZoom,
    required bool zoomingIn,
    required String moduleId,
  }) {
    return planNextTarget(
      currentZoom: currentZoom,
      cycleBaseZoom: cycleBaseZoom,
      zoomingIn: zoomingIn,
      moduleId: moduleId,
    ).targetZoom;
  }

  AutoExploreZoomAnimationPlan animationPlanForZoomLeg({
    required double startZoom,
    required double endZoom,
    required double speed,
  }) {
    final leg = AutoExploreZoomLeg.fromBounds(
      bounds: _bounds,
      startZoom: startZoom,
      endZoom: endZoom,
    );
    final effectiveSpeed = _effectiveSpeed(speed);

    final durationScale = AutoExploreDurationScale.normalize(
      config.maxDurationScale,
    );
    final normalized = AutoExploreZoomSpanScale.normalized(leg.spanDecades);
    final scale = 1.0 + normalized * (durationScale - 1.0);

    return AutoExploreZoomAnimationPlan(
      startZoom: leg.startZoom,
      endZoom: leg.endZoom,
      duration: Duration(
        milliseconds: AutoExploreLegDuration.milliseconds(
          baseDuration: config.travelDuration,
          scale: scale,
          speed: effectiveSpeed,
        ),
      ),
    );
  }

  Duration durationForZoomLeg({
    required double startZoom,
    required double endZoom,
    required double speed,
  }) {
    return animationPlanForZoomLeg(
      startZoom: startZoom,
      endZoom: endZoom,
      speed: speed,
    ).duration;
  }

  double _effectiveSpeed(double speed) => AutoExploreSpeed.normalize(speed);

  double interpolateZoom(double start, double end, double t) {
    final leg = AutoExploreZoomLeg.fromBounds(
      bounds: _bounds,
      startZoom: start,
      endZoom: end,
    );
    return leg.interpolate(t);
  }
}

import 'package:flutter_fractals/features/formulas/frm/complex.dart';
import 'package:flutter_fractals/features/formulas/frm/frm_ast.dart';
import 'package:flutter_fractals/features/formulas/frm/frm_parser.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('FrmParser (subset)', () {
    test('parses multiple formulas with init/iter sections', () {
      const src = r'''
; comment
Mandelbrot {
  z = (0,0)
  c = pixel
:
  z = z*z + c
}

Julia {
  z = pixel
  c = (0.285, 0.01)
:
  z = z*z + c
}
''';

      final file = FrmParser(src).parseFile();
      expect(
          file.formulas.map((f) => f.name).toList(), ['Mandelbrot', 'Julia']);
      expect(file.formulas[0].init.length, 2);
      expect(file.formulas[0].iter.length, 1);
    });

    test('rejects adjacent assignments without a newline separator', () {
      const src = r'''
Test {
  z = (0,0) c = pixel
:
  z = z*z + c
}
''';

      expect(
        () => FrmParser(src).parseFile(),
        throwsA(
          isA<FormatException>().having(
            (e) => e.message,
            'message',
            'Expected newline after statement',
          ),
        ),
      );
    });

    test('reports unterminated body when EOF appears before section separator',
        () {
      const src = r'''
Test {
  z = (0,0)
''';

      expect(
        () => FrmParser(src).parseFile(),
        throwsA(
          isA<FormatException>().having(
            (e) => e.message,
            'message',
            'Unterminated formula body',
          ),
        ),
      );
    });

    test('rejects complex-valued components inside complex literals', () {
      const src = r'''
Test {
  z = ((1,2), 3)
:
  z = z
}
''';

      final formula = FrmParser(src).parseFile().formulas.single;
      final ctx = FrmEvalContext(vars: {'pixel': const Complex(0, 0)});

      expect(
        () => formula.init.single.run(ctx),
        throwsA(
          isA<StateError>().having(
            (e) => e.message,
            'message',
            contains(
                'Complex literal components must evaluate to real scalars'),
          ),
        ),
      );
    });

    test('evaluates a simple iter statement', () {
      const src = r'''
Test {
  z = (0,0)
  c = (1,0)
:
  z = z*z + c
}
''';

      final formula = FrmParser(src).parseFile().formulas.single;
      final ctx = FrmEvalContext(vars: {
        'z': const Complex(0, 0),
        'c': const Complex(1, 0),
        'pixel': const Complex(0, 0),
      });

      for (final s in formula.init) {
        s.run(ctx);
      }
      // z=(0,0), c=(1,0)
      expect(ctx.vars['z']!.re, 0);
      expect(ctx.vars['c']!.re, 1);

      for (final s in formula.iter) {
        s.run(ctx);
      }
      // z = 0*0 + 1
      expect(ctx.vars['z']!.re, closeTo(1, 1e-12));
      expect(ctx.vars['z']!.im, closeTo(0, 1e-12));
    });

    test('returns immutable parse result lists', () {
      const src = r'''
Test {
  z = (0,0)
:
  z = z*z
}
''';

      final file = FrmParser(src).parseFile();
      final formula = file.formulas.single;

      expect(
        () => file.formulas.add(
          FrmFormula(name: 'Other', init: const [], iter: const []),
        ),
        throwsUnsupportedError,
      );
      expect(
        () => formula.init.add(const FrmAssign('c', FrmVar('pixel'))),
        throwsUnsupportedError,
      );
      expect(
        () => formula.iter.clear(),
        throwsUnsupportedError,
      );
    });
  });
}

// A small lexer for a restricted Fractint-like .frm subset.
//
// Supported tokens (initial subset):
// - identifiers: [A-Za-z_][A-Za-z0-9_]*
// - numbers: 123, 1.23, .5, 1e-3
// - punctuation: { } ( ) , : = + - * /
// - comments: ; to end of line

enum FrmTokKind {
  ident,
  number,
  lBrace,
  rBrace,
  lParen,
  rParen,
  comma,
  colon,
  eq,
  plus,
  minus,
  star,
  slash,
  newline,
  eof,
}

final class FrmTok {
  const FrmTok(this.kind, this.lexeme, this.offset);

  final FrmTokKind kind;
  final String lexeme;
  final int offset;

  @override
  String toString() => '$kind("$lexeme")@$offset';
}

final class FrmLexer {
  FrmLexer(this.src);

  final String src;
  int _i = 0;

  List<FrmTok> tokenize() {
    final out = <FrmTok>[];
    while (true) {
      final tok = _next();
      out.add(tok);
      if (tok.kind == FrmTokKind.eof) return out;
    }
  }

  FrmTok _next() {
    _skipSpaces();
    if (_i >= src.length) return FrmTok(FrmTokKind.eof, '', _i);

    final c = src.codeUnitAt(_i);

    // newline
    if (c == 0x0A) {
      _i++;
      return FrmTok(FrmTokKind.newline, '\n', _i - 1);
    }
    if (c == 0x0D) {
      // CRLF or CR
      final start = _i;
      _i++;
      if (_i < src.length && src.codeUnitAt(_i) == 0x0A) _i++;
      return FrmTok(FrmTokKind.newline, '\n', start);
    }

    // comment ;...
    if (c == 0x3B) {
      while (_i < src.length) {
        final cc = src.codeUnitAt(_i);
        if (cc == 0x0A || cc == 0x0D) break;
        _i++;
      }
      // emit newline separately in next call
      return _next();
    }

    switch (c) {
      case 0x7B: // {
        _i++;
        return FrmTok(FrmTokKind.lBrace, '{', _i - 1);
      case 0x7D: // }
        _i++;
        return FrmTok(FrmTokKind.rBrace, '}', _i - 1);
      case 0x28: // (
        _i++;
        return FrmTok(FrmTokKind.lParen, '(', _i - 1);
      case 0x29: // )
        _i++;
        return FrmTok(FrmTokKind.rParen, ')', _i - 1);
      case 0x2C: // ,
        _i++;
        return FrmTok(FrmTokKind.comma, ',', _i - 1);
      case 0x3A: // :
        _i++;
        return FrmTok(FrmTokKind.colon, ':', _i - 1);
      case 0x3D: // =
        _i++;
        return FrmTok(FrmTokKind.eq, '=', _i - 1);
      case 0x2B: // +
        _i++;
        return FrmTok(FrmTokKind.plus, '+', _i - 1);
      case 0x2D: // -
        _i++;
        return FrmTok(FrmTokKind.minus, '-', _i - 1);
      case 0x2A: // *
        _i++;
        return FrmTok(FrmTokKind.star, '*', _i - 1);
      case 0x2F: // /
        _i++;
        return FrmTok(FrmTokKind.slash, '/', _i - 1);
    }

    if (_isDigit(c) || c == 0x2E /* . */) {
      return _number();
    }

    if (_isAlpha(c) || c == 0x5F /* _ */) {
      return _ident();
    }

    throw FormatException('Unexpected character: ${String.fromCharCode(c)}', src, _i);
  }

  void _skipSpaces() {
    while (_i < src.length) {
      final c = src.codeUnitAt(_i);
      if (c == 0x20 || c == 0x09) {
        _i++;
        continue;
      }
      break;
    }
  }

  FrmTok _ident() {
    final start = _i;
    _i++;
    while (_i < src.length) {
      final c = src.codeUnitAt(_i);
      if (_isAlphaNum(c) || c == 0x5F) {
        _i++;
      } else {
        break;
      }
    }
    return FrmTok(FrmTokKind.ident, src.substring(start, _i), start);
  }

  FrmTok _number() {
    final start = _i;

    bool sawDigit = false;

    // int part or leading '.'
    if (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
      sawDigit = true;
      while (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
        _i++;
      }
    }

    // decimal
    if (_i < src.length && src.codeUnitAt(_i) == 0x2E /* . */) {
      _i++;
      while (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
        sawDigit = true;
        _i++;
      }
    }

    if (!sawDigit) {
      throw FormatException('Invalid number', src, start);
    }

    // exponent
    if (_i < src.length) {
      final c = src.codeUnitAt(_i);
      if (c == 0x65 /* e */ || c == 0x45 /* E */) {
        _i++;
        if (_i < src.length) {
          final s = src.codeUnitAt(_i);
          if (s == 0x2B /* + */ || s == 0x2D /* - */) _i++;
        }
        final expStart = _i;
        while (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
          _i++;
        }
        if (expStart == _i) {
          throw FormatException('Invalid exponent', src, expStart);
        }
      }
    }

    return FrmTok(FrmTokKind.number, src.substring(start, _i), start);
  }

  static bool _isDigit(int c) => c >= 0x30 && c <= 0x39;
  static bool _isAlpha(int c) => (c >= 0x41 && c <= 0x5A) || (c >= 0x61 && c <= 0x7A);
  static bool _isAlphaNum(int c) => _isAlpha(c) || _isDigit(c);
}

import 'frm_ast.dart';
import 'frm_lexer.dart';

/// Parser for a small Fractint-style .frm subset.
///
/// Current supported subset:
/// - Multiple formulas per file.
/// - `name { <init-stmts> : <iter-stmts> }`
/// - Stmts: `<ident> = <expr>` separated by newlines.
/// - Expr: numbers, identifiers, (re,im) complex literals, + - * / with parens.
///
/// This is intentionally small; we’ll extend it iteratively with functions,
/// power, comparisons, and bailout conditions once golden iteration tests are in.
bool isFrmStatementBoundary(FrmTokKind kind) =>
    kind == FrmTokKind.newline ||
    kind == FrmTokKind.colon ||
    kind == FrmTokKind.rBrace ||
    kind == FrmTokKind.eof;

bool isFrmFormulaBodyEnd(FrmTokKind kind) =>
    kind == FrmTokKind.rBrace || kind == FrmTokKind.eof;

final class FrmParser {
  FrmParser(String src) : _toks = FrmLexer(src).tokenize();

  final List<FrmTok> _toks;
  int _p = 0;

  FrmFile parseFile() {
    final formulas = <FrmFormula>[];
    _skipNewlines();
    while (!_peekIs(FrmTokKind.eof)) {
      formulas.add(_parseFormula());
      _skipNewlines();
    }
    return FrmFile(formulas);
  }

  FrmFormula _parseFormula() {
    final nameTok = _expect(FrmTokKind.ident, 'Expected formula name');
    _skipNewlines();
    _expect(FrmTokKind.lBrace, 'Expected "{" after formula name');

    final init = <FrmStmt>[];
    final iter = <FrmStmt>[];

    _skipNewlines();
    while (!_peekIs(FrmTokKind.colon)) {
      _expectInitSectionContinues();
      final stmt = _parseStmt();
      init.add(stmt);
      _skipNewlines();
    }

    _expect(FrmTokKind.colon, 'Expected ":" separating init/iter');
    _skipNewlines();

    while (!_peekIs(FrmTokKind.rBrace)) {
      if (_peekIs(FrmTokKind.eof)) {
        throw FormatException('Unterminated formula body', '', _peek().offset);
      }
      final stmt = _parseStmt();
      iter.add(stmt);
      _skipNewlines();
    }

    _expect(FrmTokKind.rBrace, 'Expected "}"');

    return FrmFormula(name: nameTok.lexeme, init: init, iter: iter);
  }

  FrmStmt _parseStmt() {
    final name = _expect(FrmTokKind.ident, 'Expected identifier').lexeme;
    _expect(FrmTokKind.eq, 'Expected "="');
    final expr = _parseExpr();
    _expectStmtBoundary();
    return FrmAssign(name, expr);
  }

  void _expectInitSectionContinues() {
    final tok = _peek();
    if (!isFrmFormulaBodyEnd(tok.kind)) return;
    if (tok.kind == FrmTokKind.eof) {
      throw FormatException('Unterminated formula body', '', tok.offset);
    }
    throw FormatException('Expected ":" in formula body', '', tok.offset);
  }

  void _expectStmtBoundary() {
    final tok = _peek();
    if (!isFrmStatementBoundary(tok.kind)) {
      throw FormatException('Expected newline after statement', '', tok.offset);
    }
  }

  FrmExpr _parseExpr() => _parseAddSub();

  FrmExpr _parseAddSub() {
    var expr = _parseMulDiv();
    while (true) {
      if (_match(FrmTokKind.plus)) {
        expr = FrmBinary(FrmBinaryOp.add, expr, _parseMulDiv());
        continue;
      }
      if (_match(FrmTokKind.minus)) {
        expr = FrmBinary(FrmBinaryOp.sub, expr, _parseMulDiv());
        continue;
      }
      return expr;
    }
  }

  FrmExpr _parseMulDiv() {
    var expr = _parsePrimary();
    while (true) {
      if (_match(FrmTokKind.star)) {
        expr = FrmBinary(FrmBinaryOp.mul, expr, _parsePrimary());
        continue;
      }
      if (_match(FrmTokKind.slash)) {
        expr = FrmBinary(FrmBinaryOp.div, expr, _parsePrimary());
        continue;
      }
      return expr;
    }
  }

  FrmExpr _parsePrimary() {
    if (_match(FrmTokKind.number)) {
      return FrmNumber(double.parse(_prev().lexeme));
    }

    if (_match(FrmTokKind.ident)) {
      return FrmVar(_prev().lexeme);
    }

    if (_match(FrmTokKind.lParen)) {
      // Could be (expr) or (re,im)
      final first = _parseExpr();
      if (_match(FrmTokKind.comma)) {
        final second = _parseExpr();
        _expect(FrmTokKind.rParen, 'Expected ")"');
        return FrmComplexLiteral(first, second);
      }
      _expect(FrmTokKind.rParen, 'Expected ")"');
      return first;
    }

    if (_match(FrmTokKind.minus)) {
      // unary minus: -x  => (0 - x)
      return FrmBinary(FrmBinaryOp.sub, const FrmNumber(0), _parsePrimary());
    }

    throw FormatException('Expected expression', '', _peek().offset);
  }

  void _skipNewlines() {
    while (_match(FrmTokKind.newline)) {}
  }

  bool _match(FrmTokKind kind) {
    if (_peekIs(kind)) {
      _p++;
      return true;
    }
    return false;
  }

  FrmTok _expect(FrmTokKind kind, String msg) {
    final tok = _peek();
    if (tok.kind != kind) {
      throw FormatException(msg, '', tok.offset);
    }
    _p++;
    return tok;
  }

  FrmTok _peek() => _toks[_p];
  FrmTok _prev() => _toks[_p - 1];
  bool _peekIs(FrmTokKind k) => _peek().kind == k;
}

import 'complex.dart';

sealed class FrmExpr {
  const FrmExpr();

  Complex eval(FrmEvalContext ctx);
}

final class FrmNumber extends FrmExpr {
  const FrmNumber(this.value);

  final double value;

  @override
  Complex eval(FrmEvalContext ctx) => Complex(value, 0);
}

final class FrmComplexLiteral extends FrmExpr {
  const FrmComplexLiteral(this.re, this.im);

  final FrmExpr re;
  final FrmExpr im;

  @override
  Complex eval(FrmEvalContext ctx) {
    final r = evalFrmRealScalarComponent(re, ctx, componentName: 'real');
    final i = evalFrmRealScalarComponent(im, ctx, componentName: 'imaginary');
    return Complex(r, i);
  }
}

/// Evaluates one component of a `(real, imaginary)` literal.
///
/// FRM complex literal components are scalar slots. Silently taking `.re` from
/// a complex-valued expression drops data and makes replay depend on an
/// undocumented truncation rule, so reject that shape at the evaluation seam.
double evalFrmRealScalarComponent(
  FrmExpr expr,
  FrmEvalContext ctx, {
  required String componentName,
}) {
  final value = expr.eval(ctx);
  if (value.im == 0.0) return value.re;
  throw StateError(
    'Complex literal components must evaluate to real scalars; '
    '$componentName component was $value',
  );
}

final class FrmVar extends FrmExpr {
  const FrmVar(this.name);

  final String name;

  @override
  Complex eval(FrmEvalContext ctx) =>
      ctx.vars[name] ?? (throw StateError('Unknown var: $name'));
}

enum FrmBinaryOp { add, sub, mul, div }

final class FrmBinary extends FrmExpr {
  const FrmBinary(this.op, this.left, this.right);

  final FrmBinaryOp op;
  final FrmExpr left;
  final FrmExpr right;

  @override
  Complex eval(FrmEvalContext ctx) {
    final a = left.eval(ctx);
    final b = right.eval(ctx);
    return switch (op) {
      FrmBinaryOp.add => a + b,
      FrmBinaryOp.sub => a - b,
      FrmBinaryOp.mul => a * b,
      FrmBinaryOp.div => a / b,
    };
  }
}

sealed class FrmStmt {
  const FrmStmt();

  void run(FrmEvalContext ctx);
}

final class FrmAssign extends FrmStmt {
  const FrmAssign(this.name, this.expr);

  final String name;
  final FrmExpr expr;

  @override
  void run(FrmEvalContext ctx) {
    ctx.vars[name] = expr.eval(ctx);
  }
}

/// Execution context for a single pixel / iteration.
final class FrmEvalContext {
  FrmEvalContext({required this.vars});

  final Map<String, Complex> vars;
}

final class FrmFormula {
  FrmFormula({
    required this.name,
    required Iterable<FrmStmt> init,
    required Iterable<FrmStmt> iter,
  })  : init = List.unmodifiable(init),
        iter = List.unmodifiable(iter);

  final String name;

  /// Statements before `:`
  final List<FrmStmt> init;

  /// Statements after `:`
  final List<FrmStmt> iter;
}

final class FrmFile {
  FrmFile(Iterable<FrmFormula> formulas)
      : formulas = List.unmodifiable(formulas);

  final List<FrmFormula> formulas;
}

/// Minimal complex number type for CPU-side formula evaluation.
///
/// We keep this tiny and allocation-light so we can evolve it into a proper
/// iteration engine later.
class Complex {
  const Complex(this.re, this.im);

  final double re;
  final double im;

  Complex operator +(Complex other) => Complex(re + other.re, im + other.im);
  Complex operator -(Complex other) => Complex(re - other.re, im - other.im);

  Complex operator *(Complex other) => Complex(
        re * other.re - im * other.im,
        re * other.im + im * other.re,
      );

  Complex operator /(Complex other) {
    final denom = other.re * other.re + other.im * other.im;
    return Complex(
      (re * other.re + im * other.im) / denom,
      (im * other.re - re * other.im) / denom,
    );
  }

  Complex scale(double s) => Complex(re * s, im * s);

  double abs2() => re * re + im * im;

  @override
  String toString() => '($re,$im)';
}

