     1	import 'package:flutter_fractals/core/models/fractal_parameter.dart';
     2	
     3	/// Numeric bounds derived from a [FractalParameter] schema.
     4	///
     5	/// Integer schemas store bounds as doubles because they share the numeric
     6	/// parameter contract with float sliders. [containsInteger] exposes the hidden
     7	/// assumption that those double bounds still include at least one valid integer
     8	/// value before integer rounding is applied.
     9	final class FractalNumericParamBounds {
    10	  const FractalNumericParamBounds({
    11	    required this.min,
    12	    required this.max,
    13	  });
    14	
    15	  factory FractalNumericParamBounds.fromSchema(FractalParameter schema) {
    16	    return FractalNumericParamBounds(min: schema.min, max: schema.max);
    17	  }
    18	
    19	  final double min;
    20	  final double max;
    21	
    22	  bool get containsInteger => min.ceil() <= max.floor();
    23	
    24	  double normalizeFloat(double value) => value.clamp(min, max).toDouble();
    25	
    26	  int normalizeInteger(double value) {
    27	    assert(
    28	      containsInteger,
    29	      'integer parameter bounds must include at least one integer value',
    30	    );
    31	    final rounded = normalizeFloat(value).round();
    32	    if (!containsInteger) return rounded;
    33	    return rounded.clamp(min.ceil(), max.floor()).toInt();
    34	  }
    35	}
    36	
    37	/// Normalizes raw parameter values against a module parameter schema.
    38	///
    39	/// This keeps replayed state, presets, and direct UI updates on the same
    40	/// contract: finite numeric values clamp to schema bounds after type coercion,
    41	/// enum values must be one of the declared options, booleans must be real
    42	/// booleans, and non-finite numeric values fall back to the schema default
    43	/// instead of being promoted to an arbitrary bound.
    44	Object normalizeFractalParamValue(FractalParameter schema, Object value) {
    45	  if (schema.type == FractalParamType.boolean) {
    46	    return value is bool ? value : _booleanDefault(schema);
    47	  }
    48	  if (schema.type == FractalParamType.enumeration) {
    49	    final optionValues = schema.options.map((option) => option.value).toSet();
    50	    return optionValues.contains(value) ? value : schema.defaultValue;
    51	  }
    52	
    53	  final numericValue = _finiteNumericValue(value);
    54	  if (numericValue != null) {
    55	    final bounds = FractalNumericParamBounds.fromSchema(schema);
    56	    if (schema.type == FractalParamType.integer) {
    57	      return bounds.normalizeInteger(numericValue);
    58	    }
    59	    return bounds.normalizeFloat(numericValue);
    60	  }
    61	  return schema.defaultValue;
    62	}
    63	
    64	double? _finiteNumericValue(Object value) {
    65	  if (value is! num) return null;
    66	  final numericValue = value.toDouble();
    67	  return numericValue.isFinite ? numericValue : null;
    68	}
    69	
    70	bool _booleanDefault(FractalParameter schema) {
    71	  final defaultValue = schema.defaultValue;
    72	  return defaultValue is bool ? defaultValue : false;
    73	}

