     1	import 'package:flutter_fractals/core/models/fractal_parameter.dart';
     2	import 'package:flutter_fractals/features/renderer/providers/fractal_param_value_normalizer.dart';
     3	import 'package:flutter_test/flutter_test.dart';
     4	
     5	String _label(_) => 'Parameter';
     6	
     7	FractalParameter _booleanParam({required bool defaultValue}) {
     8	  return FractalParameter(
     9	    id: 'enabled',
    10	    label: _label,
    11	    type: FractalParamType.boolean,
    12	    min: 0,
    13	    max: 1,
    14	    step: 1,
    15	    defaultValue: defaultValue,
    16	  );
    17	}
    18	
    19	FractalParameter _numericParam({
    20	  required FractalParamType type,
    21	  required Object defaultValue,
    22	  double min = 1,
    23	  double max = 10,
    24	}) {
    25	  return FractalParameter(
    26	    id: 'value',
    27	    label: _label,
    28	    type: type,
    29	    min: min,
    30	    max: max,
    31	    step: 1,
    32	    defaultValue: defaultValue,
    33	  );
    34	}
    35	
    36	void main() {
    37	  group('normalizeFractalParamValue', () {
    38	    test('preserves real boolean parameter values', () {
    39	      final schema = _booleanParam(defaultValue: true);
    40	
    41	      expect(normalizeFractalParamValue(schema, true), isTrue);
    42	      expect(normalizeFractalParamValue(schema, false), isFalse);
    43	    });
    44	
    45	    test('falls back to boolean schema default for non-boolean values', () {
    46	      expect(
    47	        normalizeFractalParamValue(_booleanParam(defaultValue: true), 'true'),
    48	        isTrue,
    49	      );
    50	      expect(
    51	        normalizeFractalParamValue(_booleanParam(defaultValue: false), 1),
    52	        isFalse,
    53	      );
    54	    });
    55	
    56	    test('falls back to numeric schema default for non-finite numbers', () {
    57	      final floatSchema = _numericParam(
    58	        type: FractalParamType.float,
    59	        defaultValue: 4.0,
    60	      );
    61	      final intSchema = _numericParam(
    62	        type: FractalParamType.integer,
    63	        defaultValue: 4,
    64	      );
    65	
    66	      for (final candidate in [
    67	        double.nan,
    68	        double.infinity,
    69	        double.negativeInfinity,
    70	      ]) {
    71	        expect(
    72	          normalizeFractalParamValue(floatSchema, candidate),
    73	          4.0,
    74	          reason: 'float candidate=$candidate',
    75	        );
    76	        expect(
    77	          normalizeFractalParamValue(intSchema, candidate),
    78	          4,
    79	          reason: 'integer candidate=$candidate',
    80	        );
    81	      }
    82	    });
    83	
    84	    test('keeps rounded integer values inside fractional schema bounds', () {
    85	      final schema = _numericParam(
    86	        type: FractalParamType.integer,
    87	        defaultValue: 4,
    88	        min: 1.2,
    89	        max: 10.8,
    90	      );
    91	      final bounds = FractalNumericParamBounds.fromSchema(schema);
    92	
    93	      expect(bounds.containsInteger, isTrue);
    94	      expect(normalizeFractalParamValue(schema, 1.2), 2);
    95	      expect(normalizeFractalParamValue(schema, 10.8), 10);
    96	    });
    97	  });
    98	}

